// IMPU_DATA — Dados completos dos 141 municípios de Mato Grosso
// Fonte: IBGE 2024, Estudo UFMT 2022, Portais de Transparência Municipais

export interface IMPUScore {
  dim1: number // Dimensão 1 - Plano Diretor (0-20)
  dim2: number // Dimensão 2 - Lei de Uso do Solo (0-20)
  dim3: number // Dimensão 3 - Instrumentos Complementares (0-20)
  total: number
  classif: "Crítico" | "Em Desenvolvimento" | "Estruturado"
}

export interface CidadeData {
  macro: string
  pop: number
  faixaPop: string
  turismo: boolean
  responsavel: string | null
  cargo: string | null
  telefone: string | null
  email: string | null
  pd: boolean
  pdLei: string | null
  pdAno: string | null
  pdLink: string | null
  luso: boolean
  lusoLei: string | null
  lusoAno: string | null
  lusoLink: string | null
  revPd: boolean
  revPdLei: string | null
  revPdAno: string | null
  revLuso: boolean
  revLusoLei: string | null
  revLusoAno: string | null
  obrigadoPD: boolean
  impu: IMPUScore
}

// Função para calcular classificação IMPU
function calcClassif(total: number): "Crítico" | "Em Desenvolvimento" | "Estruturado" {
  if (total < 20) return "Crítico"
  if (total < 40) return "Em Desenvolvimento"
  return "Estruturado"
}

