export function getTotalMunicipios(): number {
  return Object.keys(IMPU_DATA).length
}

export function getMunicipiosComPD(): number {
  return Object.values(IMPU_DATA).filter(m => m.pd).length
}

export function getMunicipiosComLUSO(): number {
  return Object.values(IMPU_DATA).filter(m => m.luso).length
}

export function getMunicipiosObrigadosSemPD(): CidadeData[] {
  return Object.entries(IMPU_DATA)
    .filter(([, m]) => m.obrigadoPD && !m.pd)
    .map(([nome, data]) => ({ nome, ...data })) as unknown as CidadeData[]
}

export function getMunicipiosByClassificacao(): { critico: number; emDesenvolvimento: number; estruturado: number } {
  const result = { critico: 0, emDesenvolvimento: 0, estruturado: 0 }
  Object.values(IMPU_DATA).forEach(m => {
    if (m.impu.classif === "Crítico") result.critico++
    else if (m.impu.classif === "Em Desenvolvimento") result.emDesenvolvimento++
    else result.estruturado++
  })
  return result
}

export function getMunicipiosByMacro(): Record<string, { total: number; comPD: number; comLUSO: number }> {
  const result: Record<string, { total: number; comPD: number; comLUSO: number }> = {}
  Object.values(IMPU_DATA).forEach(m => {
    if (!result[m.macro]) result[m.macro] = { total: 0, comPD: 0, comLUSO: 0 }
    result[m.macro].total++
    if (m.pd) result[m.macro].comPD++
    if (m.luso) result[m.macro].comLUSO++
  })
  return result
}

export function getPopulacaoTotal(): number {
  return Object.values(IMPU_DATA).reduce((acc, m) => acc + m.pop, 0)
}

export function getMunicipiosTuristicos(): number {
  return Object.values(IMPU_DATA).filter(m => m.turismo).length
}
